Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = Page.Rows
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'OCSDTA' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'OCSDTA' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'OCSDTA' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Ordens Produção - Costura'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount OcsTotPerCon.ColumnHeaderClass = !'WWColumn hidden-xs' OcsSts.ColumnHeaderClass = !'WWColumn hidden-xs'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Alterar.FromImage(ActionUpdate) &Alterar.TooltipText = ""
&Acoes.Clear() &Acoes.AddItem(0, 'WWP_ActionGroupCaption') &Acoes.AddItem(1, 'Lançar Quantidades') &Acoes.AddItem(2, 'Finalizar Ordem') &Acoes.AddItem(3, 'Emitir Nota') &Acoes.AddItem(4, 'Imprimir') &Acoes.AddItem(5, 'Cancelar Ordem')
&Lancamentos.FromImage(ActionDisplay) &Lancamentos.TooltipText = "Visualizar Lançamentos"
Do Case Case OcsTotPerCon = 100 OcsTotPerCon.ColumnClass = !'WWColumn hidden-xs WWColumnSuccess WWColumnSuccessSingleCell' Case OcsTotPerCon < 100 OcsTotPerCon.ColumnClass = !'WWColumn hidden-xs WWColumnDanger WWColumnDangerSingleCell' Otherwise OcsTotPerCon.ColumnClass = 'WWColumn hidden-xs' EndCase Do Case Case OcsSts = Status_Pedido.Aberto OcsSts.ColumnClass = !'WWColumn hidden-xs WWColumnSuccess WWColumnSuccessSingleCell' Case OcsSts = Status_Pedido.Fechado OcsSts.ColumnClass = !'WWColumn hidden-xs WWColumnBold WWColumnBoldSingleCell' Case OcsSts = Status_Pedido.Cancelado OcsSts.ColumnClass = !'WWColumn hidden-xs WWColumnDanger WWColumnDangerSingleCell' Otherwise OcsSts.ColumnClass = 'WWColumn hidden-xs' EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = True AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersIgnoreFirst = True Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False &DynamicFiltersIgnoreFirst = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector1.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters1'
